#include<bits/stdc++.h>
using namespace std;
int b[3],i;
int main() {
	string s;
	getline(cin,s);
	for(i=0; i<s.size();) {
		if(s[i]=='a') {
			if(s[i+3]=='a') b[1]=b[1];
			else if(s[i+3]=='b') b[1]=b[2];
			else if(s[i+3]=='c') b[1]=b[3];
			else b[1]=s[i+3]-'0';
		}
		if(s[i]=='b') {
			if(s[i+3]=='b') b[2]=b[2];
			else if(s[i+3]=='a') b[2]=b[1];
			else if(s[i+3]=='c') b[2]=b[3];
			else b[2]=s[i+3]-'0';
		}
		if(s[i]=='c') {
			if(s[i+3]=='c') b[3]=b[3];
			else if(s[i+3]=='a') b[3]=b[1];
			else if(s[i+3]=='b') b[3]=b[2];
			else b[3]=s[i+3]-'0';
		}
		i+=5;
	}
	cout<<b[1]<<" "<<b[2]<<" "<<b[3];
	return 0;
}
